class Solution {
    public int shipWithinDays(int[] weights, int days) {
        int left = getMax(weights), right = getSum(weights);
        while (left < right) {
            int mid = left + (right - left) / 2;
            if (canShipWithinDays(weights, mid, days)) {
                right = mid;
            } else {
                left = mid + 1;
            }
        }
        return left;
    }

    private boolean canShipWithinDays(int[] weights, int capacity, int days) {
        int currentCapacity = 0, currentDays = 1;
        for (int weight : weights) {
            if (currentCapacity + weight > capacity) {
                currentDays++;
                currentCapacity = 0;
            }
            currentCapacity += weight;
        }
        return currentDays <= days;
    }

    private int getMax(int[] weights) {
        int max = Integer.MIN_VALUE;
        for (int weight : weights) {
            max = Math.max(max, weight);
        }
        return max;
    }

    private int getSum(int[] weights) {
        int sum = 0;
        for (int weight : weights) {
            sum += weight;
        }
        return sum;
    }
}

